import {
  Box,
  Button,
  Flex,
  Grid,
  Image,
  Text,
  Textarea,
} from "@chakra-ui/react";
import React, { useState } from "react";
import AdminNavTop from "../AdminNavTop";

const data = [
  {
    image:
      "https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcRzShY-HQBduoJukm8zwN-869tlTb7Dl2sxlw&usqp=CAU",
    desc: "50% Discount available",
    id: 1,
    status: true,
  },
  {
    image:
      "https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcRzShY-HQBduoJukm8zwN-869tlTb7Dl2sxlw&usqp=CAU",
    desc: "50% Discount available",
    id: 2,
    status: true,
  },
  {
    image:
      "https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcRzShY-HQBduoJukm8zwN-869tlTb7Dl2sxlw&usqp=CAU",
    desc: "50% Discount available",
    id: 3,
    status: true,
  },
  {
    image:
      "https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcRzShY-HQBduoJukm8zwN-869tlTb7Dl2sxlw&usqp=CAU",
    desc: "50% Discount available",
    id: 4,
    status: true,
  },
  {
    image:
      "https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcRzShY-HQBduoJukm8zwN-869tlTb7Dl2sxlw&usqp=CAU",
    desc: "50% Discount available",
    id: 5,
    status: true,
  },
  {
    image:
      "https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcRzShY-HQBduoJukm8zwN-869tlTb7Dl2sxlw&usqp=CAU",
    desc: "50% Discount available",
    id: 6,
    status: true,
  },
  {
    image:
      "https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcRzShY-HQBduoJukm8zwN-869tlTb7Dl2sxlw&usqp=CAU",
    desc: "50% Discount available",
    id: 7,
    status: true,
  },
  {
    image:
      "https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcRzShY-HQBduoJukm8zwN-869tlTb7Dl2sxlw&usqp=CAU",
    desc: "50% Discount available",
    id: 8,
    status: true,
  },
  {
    image:
      "https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcRzShY-HQBduoJukm8zwN-869tlTb7Dl2sxlw&usqp=CAU",
    desc: "50% Discount available",
    id: 9,
    status: true,
  },
  {
    image:
      "https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcRzShY-HQBduoJukm8zwN-869tlTb7Dl2sxlw&usqp=CAU",
    desc: "50% Discount available",
    id: 10,
    status: true,
  },
];

const GiftCard = () => {
  const [discount, setDiscount] = useState(data);

  const newArray = [...discount];

  const handleDelete = (id) => {
    let data = discount.filter((el) => {
      return el.id !== id;
    });
    setDiscount(data);
  };
  const handleClick = (id) => {
    // console.log(id)
  };

  return (
  <Box bg="#f7f9fa" minH="100vh" p={6}>
    <AdminNavTop />

    <Box mt="80px">
      <Text fontSize="2xl" fontWeight="bold" mb={6}>
        Gift Cards
      </Text>

      <Grid
        templateColumns={{
          base: "1fr",
          md: "repeat(2,1fr)",
          lg: "repeat(3,1fr)",
        }}
        gap={6}
      >
        {discount.map((el) => (
          <Box
            key={el.id}
            bg="white"
            borderRadius="lg"
            overflow="hidden"
            boxShadow="lg"
            _hover={{
              transform: "translateY(-5px)",
              transition: "0.2s",
            }}
          >
            {/* IMAGE */}
            <Box position="relative">
              <Image
                src={el.image}
                w="100%"
                h="180px"
                objectFit="cover"
              />

              {/* STATUS BADGE */}
              <Box
                position="absolute"
                top="10px"
                right="10px"
                bg={el.status ? "green.500" : "gray.400"}
                color="white"
                px={3}
                py={1}
                borderRadius="md"
                fontSize="sm"
              >
                {el.status ? "Active" : "Disabled"}
              </Box>
            </Box>

            {/* CONTENT */}
            <Box p={4}>
              <Text fontWeight="bold" mb={3}>
                {el.desc}
              </Text>

              <Flex justify="space-between">
                <Button
                  size="sm"
                  colorScheme="red"
                  variant="outline"
                  onClick={() => handleDelete(el.id)}
                >
                  Delete
                </Button>

                <Button
                  size="sm"
                  bg="#A435F0"
                  color="white"
                  _hover={{ bg: "#8710d8" }}
                  onClick={() => handleClick(el.id)}
                >
                  {el.status ? "Disable" : "Enable"}
                </Button>
              </Flex>
            </Box>
          </Box>
        ))}
      </Grid>
    </Box>
  </Box>
);
};

export default GiftCard;
